completionScripts.powershell:
# privacy-pools PowerShell completion
Register-ArgumentCompleter -CommandName privacy-pools -ScriptBlock {
    param($wordToComplete, $commandAst, $cursorPosition)
    $words = $commandAst.ToString() -split '\s+'
    $cword = $words.Count - 1
    if ($wordToComplete -eq '') { $cword = $words.Count; $words += '' }
    $candidates = & privacy-pools completion --query --shell powershell --cword $cword -- @words 2>$null
    if ($candidates) {
        $candidates -split '\n' | Where-Object { $_ -ne '' } | ForEach-Object {
            [System.Management.Automation.CompletionResult]::new($_, $_, 'ParameterValue', $_)
        }
    }
}
